Create a `create_index.go` file in your project directory,
and copy and paste the following code into the file.```go
package main

import (
	"context"
	"fmt"
	"log"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	ctx := context.Background()
	uri := "<connection-string>"
	client, err := mongo.Connect(options.Client().
		ApplyURI(uri))
	if err != nil {
		panic(err)
	}

	defer func() {
		if err := client.Disconnect(context.TODO()); err != nil {
			panic(err)
		}
	}()

	coll := client.Database("local_school_district").Collection("schools")
	const indexName = "embedded-documents-tutorial"
	opts := options.SearchIndexes().SetName(indexName).SetType("search")

	// Define the Atlas Search index for embedded documents
	searchIndexModel := mongo.SearchIndexModel{
		Definition: bson.D{
			{"mappings", bson.D{
				{"dynamic", true},
				{"fields", bson.D{
					{"clubs", bson.D{
						{"dynamic", true},
						{"fields", bson.D{
							{"sports", bson.D{
								{"dynamic", true},
								{"type", "embeddedDocuments"},
							}},
						}},
						{"type", "document"},
					}},
					{"teachers", bson.A{
						bson.D{
							{"dynamic", true},
							{"fields", bson.D{
								{"classes", bson.D{
									{"dynamic", true},
									{"type", "embeddedDocuments"},
								}},
							}},
							{"type", "embeddedDocuments"},
						},
						bson.D{
							{"dynamic", true},
							{"fields", bson.D{
								{"classes", bson.D{
									{"dynamic", true},
									{"fields", bson.D{
										{"grade", bson.D{
											{"type", "token"},
										}},
									}},
									{"type", "document"},
								}},
							}},
							{"type", "document"},
						},
					}},
				}},
			}},
		},
		Options: opts,
	}

	// Create the index
	searchIndexName, err := coll.SearchIndexes().CreateOne(ctx, searchIndexModel)
	if err != nil {
		log.Fatalf("Failed to create the Atlas Search index: %v", err)
	}

	fmt.Println("Name of index created: " + searchIndexName)
}
```Atlas ClusterReplace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.Atlas ClusterYour connection string should use the following format:```
mongodb+srv://<db_username>:<db_password>@<clusterName>.<hostname>.mongodb.net
```To learn more, see [Driver](connect-via-driver).Local or Self-ManagedYour connection string should use the
following format:```
mongodb://localhost:<port-number>/?directConnection=true
```To learn more, see [Connection Strings](manual/reference/connection-string).IMPORTANT: Ensure that your connection string includes your database
user's credentials. To learn more about finding your connection string,
see [Driver](connect-via-driver).Local DeploymentYour connection string should use the following format:```
mongodb://localhost:<port-number>/?directConnection=true
```

